import{_ as o,c as d,a3 as i,o as c}from"./chunks/framework.VX8o9GSp.js";const n=JSON.parse('{"title":"vscode snippets 预置变量","description":"","frontmatter":{"date":"2024-05-01T00:00:00.000Z","tags":["vscode"],"categories":["计算机"]},"headers":[],"relativePath":"2024/05/vscode snippets 预置变量.md","filePath":"2024/05/vscode snippets 预置变量.md","lastUpdated":1728748308000}'),l={name:"2024/05/vscode snippets 预置变量.md"};function s(t,e,a,_,p,r){return c(),d("div",null,e[0]||(e[0]=[i('<h1 id="vscode-snippets-预置变量" tabindex="-1">vscode snippets 预置变量 <a class="header-anchor" href="#vscode-snippets-预置变量" aria-label="Permalink to &quot;vscode snippets 预置变量&quot;">​</a></h1><p>在 Visual Studio Code 中，你可以使用许多预定义的变量来创建代码片段（snippets）。以下是一些常用的预定义变量：</p><ul><li><code>$TM_SELECTED_TEXT</code>：当前选中的文本。</li><li><code>$TM_CURRENT_LINE</code>：当前行的内容。</li><li><code>$TM_CURRENT_WORD</code>：光标下的单词内容。</li><li><code>$TM_LINE_INDEX</code>：当前行的索引（基于0）。</li><li><code>$TM_LINE_NUMBER</code>：当前行号（基于1）。</li><li><code>$TM_FILENAME</code>：当前文档的文件名。</li><li><code>$TM_FILENAME_BASE</code>：当前文档的文件名，不包含扩展名。</li><li><code>$TM_DIRECTORY</code>：当前文档的目录。</li><li><code>$TM_FILEPATH</code>：当前文档的完整文件路径。</li><li><code>$CLIPBOARD</code>：剪贴板的内容。</li><li><code>$WORKSPACE_NAME</code>：打开的工作区的名称。</li></ul><p>你也可以使用如下的特殊变量：</p><ul><li><code>$CURRENT_YEAR</code>：当前年份。</li><li><code>$CURRENT_YEAR_SHORT</code>：当前年份的最后两位数字。</li><li><code>$CURRENT_MONTH</code>：当前月份。</li><li><code>$CURRENT_DATE</code>：当前日期。</li><li><code>$CURRENT_HOUR</code>：当前小时。</li><li><code>$CURRENT_MINUTE</code>：当前分钟。</li><li><code>$CURRENT_SECOND</code>：当前秒数。</li><li><code>$CURRENT_SECONDS_UNIX</code>：当前 Unix 时间戳。</li></ul><p>更多关于代码片段的信息，你可以参考 <a href="https://code.visualstudio.com/docs/editor/userdefinedsnippets#_variables" target="_blank" rel="noreferrer">Visual Studio Code 的官方文档</a>。</p>',6)]))}const R=o(l,[["render",s]]);export{n as __pageData,R as default};
